renda = float(input("Renda familiar (R$): "))
vulneravel = input("Tem vulnerável? (sim/nao): ") == "sim"

# Aninhado: mensagens por nível
if renda <= 2640.0:
    print("Elegível MCMV.")
    if vulneravel:
        print("Prioridade ALTA.")

# Versão com and: ação única combinada
if renda <= 2640.0 and vulneravel:
    print("(combinado) Encaminhar para fila ALTA.")

bioma = input("Bioma (amazonia/cerrado/outros): ").lower()
focos = int(input("Focos detectados hoje: "))

if focos > 0:
    print(f"Focos registrados: {focos}")
    if bioma == "amazonia":
        if focos >= 50:
            print("ALERTA: CRÍTICO — Amazônia em emergência")
        elif focos >= 20:
            print("ALERTA: ALTO")
        else:
            print("ALERTA: MODERADO")
    elif bioma == "cerrado":
        if focos >= 100:
            print("ALERTA: CRÍTICO — Cerrado em colapso")
        else:
            print("ALERTA: ATENÇÃO")
    else:
        print("ALERTA: REGISTRADO — protocolo padrão")
else:
    print("Sem focos detectados hoje — situação normal")
